# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os
from enum import IntEnum
from typing import Optional
from datetime import datetime


class AccessLevel(IntEnum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class PermissionDeniedError(Exception):
    """Raised when a user does not have permission to access a file."""
    pass


class FileNotFoundError(Exception):
    """Raised when the requested file does not exist."""
    pass


class UserNotFoundError(Exception):
    """Raised when the user does not exist in the system."""
    pass


class FileAccessControlSystem:
    def __init__(self, db_path: str = ":memory:", file_storage_root: str = "./documents"):
        self.db_path = db_path
        self.file_storage_root = file_storage_root
        self._init_database()

    def _get_connection(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA foreign_keys = ON")
        return conn

    def _init_database(self):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.executescript("""
                CREATE TABLE IF NOT EXISTS users (
                    user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT UNIQUE NOT NULL,
                    is_active BOOLEAN DEFAULT 1,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                );

                CREATE TABLE IF NOT EXISTS files (
                    file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    filename TEXT NOT NULL,
                    file_path TEXT UNIQUE NOT NULL,
                    owner_id INTEGER NOT NULL,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (owner_id) REFERENCES users(user_id)
                );

                CREATE TABLE IF NOT EXISTS permissions (
                    permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    access_level INTEGER NOT NULL DEFAULT 0,
                    granted_by INTEGER,
                    granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    expires_at TIMESTAMP,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id),
                    FOREIGN KEY (granted_by) REFERENCES users(user_id),
                    UNIQUE(user_id, file_id)
                );

                CREATE TABLE IF NOT EXISTS access_log (
                    log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    action TEXT NOT NULL,
                    success BOOLEAN NOT NULL,
                    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    details TEXT,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id)
                );

                CREATE INDEX IF NOT EXISTS idx_permissions_user_file 
                    ON permissions(user_id, file_id);
                CREATE INDEX IF NOT EXISTS idx_access_log_user 
                    ON access_log(user_id);
                CREATE INDEX IF NOT EXISTS idx_access_log_file 
                    ON access_log(file_id);
            """)
            conn.commit()
        finally:
            conn.close()

    def add_user(self, username: str) -> int:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO users (username) VALUES (?)",
                (username,)
            )
            conn.commit()
            return cursor.lastrowid
        finally:
            conn.close()

    def register_file(self, filename: str, file_path: str, owner_id: int) -> int:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO files (filename, file_path, owner_id) VALUES (?, ?, ?)",
                (filename, file_path, owner_id)
            )
            file_id = cursor.lastrowid
            # Owner automatically gets admin access
            cursor.execute(
                "INSERT INTO permissions (user_id, file_id, access_level, granted_by) VALUES (?, ?, ?, ?)",
                (owner_id, file_id, AccessLevel.ADMIN, owner_id)
            )
            conn.commit()
            return file_id
        finally:
            conn.close()

    def grant_permission(self, grantor_id: int, user_id: int, file_id: int,
                         access_level: AccessLevel, expires_at: Optional[str] = None):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()

            # Check if grantor has admin access
            grantor_level = self._get_access_level(cursor, grantor_id, file_id)
            if grantor_level < AccessLevel.ADMIN:
                raise PermissionDeniedError(
                    f"User {grantor_id} does not have admin permission to grant access to file {file_id}"
                )

            cursor.execute("""
                INSERT INTO permissions (user_id, file_id, access_level, granted_by, expires_at)
                VALUES (?, ?, ?, ?, ?)
                ON CONFLICT(user_id, file_id) 
                DO UPDATE SET access_level = ?, granted_by = ?, granted_at = CURRENT_TIMESTAMP, expires_at = ?
            """, (user_id, file_id, access_level, grantor_id, expires_at,
                  access_level, grantor_id, expires_at))
            conn.commit()
        finally:
            conn.close()

    def revoke_permission(self, grantor_id: int, user_id: int, file_id: int):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()

            grantor_level = self._get_access_level(cursor, grantor_id, file_id)
            if grantor_level < AccessLevel.ADMIN:
                raise PermissionDeniedError(
                    f"User {grantor_id} does not have admin permission to revoke access to file {file_id}"
                )

            cursor.execute(
                "UPDATE permissions SET access_level = ? WHERE user_id = ? AND file_id = ?",
                (AccessLevel.NONE, user_id, file_id)
            )
            conn.commit()
        finally:
            conn.close()

    def _get_access_level(self, cursor, user_id: int, file_id: int) -> AccessLevel:
        # Check user exists and is active
        cursor.execute(
            "SELECT is_active FROM users WHERE user_id = ?",
            (user_id,)
        )
        user = cursor.fetchone()
        if user is None:
            raise UserNotFoundError(f"User {user_id} not found")
        if not user['is_active']:
            return AccessLevel.NONE

        cursor.execute("""
            SELECT access_level, expires_at 
            FROM permissions 
            WHERE user_id = ? AND file_id = ?
        """, (user_id, file_id))
        row = cursor.fetchone()

        if row is None:
            return AccessLevel.NONE

        # Check if permission has expired
        if row['expires_at'] is not None:
            expires = datetime.fromisoformat(row['expires_at'])
            if datetime.now() > expires:
                # Clean up expired permission
                cursor.execute(
                    "UPDATE permissions SET access_level = ? WHERE user_id = ? AND file_id = ?",
                    (AccessLevel.NONE, user_id, file_id)
                )
                return AccessLevel.NONE

        return AccessLevel(row['access_level'])

    def check_permission(self, user_id: int, file_id: int,
                         required_level: AccessLevel = AccessLevel.READ) -> bool:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            level = self._get_access_level(cursor, user_id, file_id)
            conn.commit()  # In case expired permissions were cleaned up
            return level >= required_level
        finally:
            conn.close()

    def _log_access(self, cursor, user_id: int, file_id: int,
                    action: str, success: bool, details: Optional[str] = None):
        cursor.execute("""
            INSERT INTO access_log (user_id, file_id, action, success, details)
            VALUES (?, ?, ?, ?, ?)
        """, (user_id, file_id, action, success, details))

    def read_file(self, user_id: int, file_id: int) -> str:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()

            # Get file info
            cursor.execute(
                "SELECT filename, file_path FROM files WHERE file_id = ?",
                (file_id,)
            )
            file_record = cursor.fetchone()
            if file_record is None:
                self._log_access(cursor, user_id, file_id, "READ", False, "File not found in database")
                conn.commit()
                raise FileNotFoundError(f"File with id {file_id} not found in the system")

            # Check permission
            access_level = self._get_access_level(cursor, user_id, file_id)
            if access_level < AccessLevel.READ:
                self._log_access(cursor, user_id, file_id, "READ", False,
                                 f"Insufficient permissions. Level: {access_level}")
                conn.commit()
                raise PermissionDeniedError(
                    f"User {user_id} does not have read permission for file {file_id} "
                    f"('{file_record['filename']}')"
                )

            # Read the actual file
            full_path = os.path.join(self.file_storage_root, file_record['file_path'])
            if not os.path.exists(full_path):
                self._log_access(cursor, user_id, file_id, "READ", False,
                                 "File not found on disk")
                conn.commit()
                raise FileNotFoundError(
                    f"File '{file_record['filename']}' not found on disk at {full_path}"
                )

            with open(full_path, 'r', encoding='utf-8') as f:
                contents = f.read()

            self._log_access(cursor, user_id, file_id, "READ", True)
            conn.commit()
            return contents

        finally:
            conn.close()

    def get_access_log(self, file_id: Optional[int] = None,
                       user_id: Optional[int] = None, limit: int = 100) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            query = """
                SELECT al.*, u.username, f.filename 
                FROM access_log al
                JOIN users u ON al.user_id = u.user_id
                JOIN files f ON al.file_id = f.file_id
                WHERE 1=1
            """
            params = []

            if file_id is not None:
                query += " AND al.file_id = ?"
                params.append(file_id)
            if user_id is not None:
                query += " AND al.user_id = ?"
                params.append(user_id)

            query += " ORDER BY al.timestamp DESC LIMIT ?"
            params.append(limit)

            cursor.execute(query, params)
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def get_user_permissions(self, user_id: int) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute("""
                SELECT p.*, f.filename, f.file_path,
                       u.username as granted_by_username
                FROM permissions p
                JOIN files f ON p.file_id = f.file_id
                LEFT JOIN users u ON p.granted_by = u.user_id
                WHERE p.user_id = ? AND p.access_level > 0
                ORDER BY f.filename
            """, (user_id,))
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def get_file_permissions(self, file_id: int) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute("""
                SELECT p.*, u.username,
                       g.username as granted_by_username
                FROM permissions p
                JOIN users u ON p.user_id = u.user_id
                LEFT JOIN users g ON p.granted_by = g.user_id
                WHERE p.file_id = ? AND p.access_level > 0
                ORDER BY p.access_level DESC
            """, (file_id,))
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def deactivate_user(self, admin_id: int, user_id: int):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "UPDATE users SET is_active = 0 WHERE user_id = ?",
                (user_id,)
            )
            conn.commit()
        finally:
            conn.close()


def main():
    """Demo of the file access control system."""
    import tempfile
    import shutil

    # Create temporary directory for documents
    doc_root = tempfile.mkdtemp(prefix="doc_mgmt_")

    try:
        system = FileAccessControlSystem(db_path=":memory:", file_storage_root=doc_root)

        # Create users
        alice_id = system.add_user("alice")
        bob_id = system.add_user("bob")
        charlie_id = system.add_user("charlie")
        print(f"Created users: alice({alice_id}), bob({bob_id}), charlie({charlie_id})")

        # Create some document files on disk
        doc1_path = "reports/quarterly_report.txt"
        doc2_path = "memos/confidential_memo.txt"

        os.makedirs(os.path.join(doc_root, "reports"), exist_ok=True)
        os.makedirs(os.path.join(doc_root, "memos"), exist_ok=True)

        with open(os.path.join(doc_root, doc1_path), 'w') as f:
            f.write("Q3 2024 Quarterly Report\n\nRevenue: $1.2M\nExpenses: $800K\nProfit: $400K")

        with open(os.path.join(doc_root, doc2_path), 'w') as f:
            f.write("CONFIDENTIAL MEMO\n\nProject Phoenix launch date: January 15, 2025")

        # Register files in the system
        file1_id = system.register_file("Quarterly Report", doc1_path, alice_id)
        file2_id = system.register_file("Confidential Memo", doc2_path, alice_id)
        print(f"\nRegistered files: report({file1_id}), memo({file2_id})")

        # Alice (owner) reads her own file
        print("\n--- Alice reads the quarterly report ---")
        try:
            contents = system.read_file(alice_id, file1_id)
            print(f"Success! Contents:\n{contents}")
        except PermissionDeniedError as e:
            print(f"Denied: {e}")

        # Bob tries to read without permission
        print("\n--- Bob tries to read the quarterly report (no permission) ---")
        try:
            contents = system.read_file(bob_id, file1_id)
            print(f"Success! Contents:\n{contents}")
        except PermissionDeniedError as e:
            print(f"Denied: {e}")

        # Alice grants Bob read access
        print("\n--- Alice grants Bob read access to the report ---")
        system.grant_permission(alice_id, bob_id, file1_id, AccessLevel.READ)

        # Bob tries again
        print("\n--- Bob reads the quarterly report (with permission) ---")
        try:
            contents = system.read_file(bob_id, file1_id)
            print(f"Success! Contents:\n{contents}")
        except PermissionDeniedError as e:
            print(f"Denied: {e}")

        # Charlie tries to read confidential memo
        print("\n--- Charlie tries to read the confidential memo ---")
        try:
            contents = system.read_file(charlie_id, file2_id)
            print(f"Success! Contents:\n{contents}")
        except PermissionDeniedError as e:
            print(f"Denied: {e}")

        # Bob tries to grant permissions (should fail - not admin)
        print("\n--- Bob tries to grant Charlie access (not admin) ---")
        try:
            system.grant_permission(bob_id, charlie_id, file1_id, AccessLevel.READ)
            print("Permission granted successfully")
        except PermissionDeniedError as e:
            print(f"Denied: {e}")

        # Alice grants Charlie time-limited access (already expired for demo)
        print("\n--- Alice grants Charlie expired access to the memo ---")
        system.grant_permission(alice_id, charlie_id, file2_id, AccessLevel.READ,
                                expires_at="2020-01-01T00:00:00")

        print("\n--- Charlie tries to read with expired permission ---")
        try:
            contents = system.read_file(charlie_id, file2_id)
            print(f"Success! Contents:\n{contents}")
        except PermissionDeniedError as e:
            print(f"Denied: {e}")

        # Alice revokes Bob's access
        print("\n--- Alice revokes Bob's access to the report ---")
        system.revoke_permission(alice_id, bob_id, file1_id)

        print("\n--- Bob tries to read after revocation ---")
        try:
            contents = system.read_file(bob_id, file1_id)
            print(f"Success! Contents:\n{contents}")
        except PermissionDeniedError as e:
            print(f"Denied: {e}")

        # Show permissions for the quarterly report
        print("\n--- File permissions for Quarterly Report ---")
        perms = system.get_file_permissions(file1_id)
        for p in perms:
            print(f"  User: {p['username']}, Level: {AccessLevel(p['access_level']).name}, "
                  f"Granted by: {p['granted_by_username']}")

        # Show access log
        print("\n--- Access Log ---")
        logs = system.get_access_log()
        for log in logs:
            status = "✓" if log['success'] else "✗"
            print(f"  [{status}] {log['username']} -> {log['filename']} "
                  f"({log['action']}) at {log['timestamp']}"
                  f"{' - ' + log['details'] if log['details'] else ''}")

        # Check permission programmatically
        print("\n--- Permission checks ---")
        print(f"Alice READ report: {system.check_permission(alice_id, file1_id, AccessLevel.READ)}")
        print(f"Alice ADMIN report: {system.check_permission(alice_id, file1_id, AccessLevel.ADMIN)}")
        print(f"Bob READ report: {system.check_permission(bob_id, file1_id, AccessLevel.READ)}")

        # Show user permissions
        print("\n--- Alice's permissions ---")
        alice_perms = system.get_user_permissions(alice_id)
        for p in alice_perms:
            print(f"  File: {p['filename']}, Level: {AccessLevel(p['access_level']).name}")

    finally:
        shutil.rmtree(doc_root, ignore_errors=True)


if __name__ == "__main__":
    main()